<?php
/**
 * Plugin Name: Tager V32 Account Experience
 * Description: Expanded post-login dashboards for vendors and customers with navigation, profile, addresses, products, orders and earnings.
 * Version: 32.0.0
 */
if (!defined('ABSPATH')) exit;

class Tager_V32_Account_Experience {
    const VERSION='32.0.0';

    public static function init(){
        add_action('init',[__CLASS__,'override_shortcodes'],999);
        add_action('wp_enqueue_scripts',[__CLASS__,'assets'],99);
        add_action('admin_post_tager_v32_save_customer',[__CLASS__,'save_customer']);
        add_action('admin_post_tager_v32_save_vendor',[__CLASS__,'save_vendor']);
    }

    public static function override_shortcodes(){
        remove_shortcode('tager_customer_account');
        remove_shortcode('tager_vendor_dashboard');
        add_shortcode('tager_customer_account',[__CLASS__,'customer_account']);
        add_shortcode('tager_vendor_dashboard',[__CLASS__,'vendor_dashboard']);
    }

    private static function lang(){ return (isset($_GET['lang']) && $_GET['lang']==='en') ? 'en':'ar'; }
    private static function t($ar,$en){ return self::lang()==='en'?$en:$ar; }
    private static function url($slug){ $p=get_option('tager_pages',[]); return isset($p[$slug])?get_permalink($p[$slug]):home_url('/'.$slug.'/'); }
    private static function tab_url($base,$tab){ return add_query_arg(['tab'=>$tab],self::url($base)); }
    private static function money($v){ return number_format((float)$v,2).' EGP'; }
    private static function status_badge($status){$key=strtolower(str_replace(' ','-',trim((string)$status)));return '<span class="t32-badge t32-'.$key.'">'.esc_html($status?:self::t('غير محدد','Unknown')).'</span>';}

    public static function assets(){
        wp_add_inline_style('tager-style', self::css());
    }

    private static function shell($kind,$title,$subtitle,$tabs,$active,$content){
        ob_start(); ?>
        <div class="t32-shell t32-<?php echo esc_attr($kind); ?>">
          <aside class="t32-sidebar">
            <div class="t32-brand"><span class="t32-logo">T</span><div><strong>Tager</strong><small><?php echo esc_html($kind==='vendor'?self::t('مركز المورد','Vendor Center'):self::t('حساب العميل','Customer Account')); ?></small></div></div>
            <nav class="t32-nav">
              <?php foreach($tabs as $key=>$tab): ?><a class="<?php echo $active===$key?'active':''; ?>" href="<?php echo esc_url($tab['url']); ?>"><span><?php echo esc_html($tab['icon']); ?></span><?php echo esc_html($tab['label']); ?></a><?php endforeach; ?>
            </nav>
            <div class="t32-side-foot"><a href="<?php echo esc_url(home_url('/')); ?>">⌂ <?php echo esc_html(self::t('العودة للموقع','Back to site')); ?></a><a href="<?php echo esc_url(wp_logout_url(home_url('/'))); ?>">↪ <?php echo esc_html(self::t('تسجيل الخروج','Sign out')); ?></a></div>
          </aside>
          <main class="t32-main">
            <header class="t32-top"><div><h1><?php echo esc_html($title); ?></h1><p><?php echo esc_html($subtitle); ?></p></div><div class="t32-actions"><a class="btn secondary" href="<?php echo esc_url(add_query_arg('lang',self::lang()==='ar'?'en':'ar')); ?>"><?php echo self::lang()==='ar'?'EN':'AR'; ?></a></div></header>
            <?php if(!empty($_GET['saved'])): ?><div class="notice success"><?php echo esc_html(self::t('تم حفظ البيانات بنجاح.','Your changes were saved.')); ?></div><?php endif; ?>
            <section class="t32-content"><?php echo $content; ?></section>
          </main>
        </div>
        <?php return ob_get_clean();
    }

    private static function customer_tabs(){
        return [
            'overview'=>['icon'=>'⌂','label'=>self::t('نظرة عامة','Overview'),'url'=>self::tab_url('my-account','overview')],
            'orders'=>['icon'=>'▣','label'=>self::t('طلباتي','My orders'),'url'=>self::tab_url('my-account','orders')],
            'addresses'=>['icon'=>'⌖','label'=>self::t('العناوين','Addresses'),'url'=>self::tab_url('my-account','addresses')],
            'favorites'=>['icon'=>'♡','label'=>self::t('المفضلة','Favorites'),'url'=>self::tab_url('my-account','favorites')],
            'profile'=>['icon'=>'◉','label'=>self::t('الملف الشخصي','Profile'),'url'=>self::tab_url('my-account','profile')],
            'support'=>['icon'=>'?','label'=>self::t('الدعم','Support'),'url'=>self::tab_url('my-account','support')],
        ];
    }

    private static function vendor_tabs(){
        return [
            'overview'=>['icon'=>'⌂','label'=>self::t('لوحة التحكم','Dashboard'),'url'=>self::tab_url('vendor-dashboard','overview')],
            'products'=>['icon'=>'▦','label'=>self::t('المنتجات','Products'),'url'=>self::tab_url('vendor-dashboard','products')],
            'add-product'=>['icon'=>'+','label'=>self::t('إضافة منتج','Add product'),'url'=>self::tab_url('vendor-dashboard','add-product')],
            'orders'=>['icon'=>'▣','label'=>self::t('الطلبات','Orders'),'url'=>self::tab_url('vendor-dashboard','orders')],
            'earnings'=>['icon'=>'$','label'=>self::t('الأرباح','Earnings'),'url'=>self::tab_url('vendor-dashboard','earnings')],
            'store'=>['icon'=>'◫','label'=>self::t('إعدادات المتجر','Store settings'),'url'=>self::tab_url('vendor-dashboard','store')],
            'profile'=>['icon'=>'◉','label'=>self::t('الحساب والأمان','Account & security'),'url'=>self::tab_url('vendor-dashboard','profile')],
        ];
    }

    public static function customer_account(){
        if(!is_user_logged_in()) return self::login_box('customer');
        $u=wp_get_current_user();
        if(in_array('tager_vendor',$u->roles,true)||in_array('tager_vendor_pending',$u->roles,true)) return '<div class="form-wrap"><a class="btn primary" href="'.esc_url(self::url('vendor-dashboard')).'">'.esc_html(self::t('فتح لوحة المورد','Open vendor dashboard')).'</a></div>';
        $tab=sanitize_key($_GET['tab']??'overview'); if(!isset(self::customer_tabs()[$tab]))$tab='overview';
        $content='';
        if($tab==='overview') $content=self::customer_overview($u);
        elseif($tab==='orders') $content=self::customer_orders($u);
        elseif($tab==='addresses') $content=self::customer_addresses($u);
        elseif($tab==='favorites') $content=self::customer_favorites();
        elseif($tab==='profile') $content=self::customer_profile($u);
        else $content=self::support_panel();
        return self::shell('customer',self::t('مرحبًا، ','Welcome, ').$u->display_name,self::t('تابع طلباتك وبيانات حسابك من مكان واحد.','Manage your orders and account from one place.'),self::customer_tabs(),$tab,$content);
    }

    private static function login_box($type){ob_start();?><section class="t32-login"><div><span class="eyebrow">Tager</span><h1><?php echo esc_html($type==='vendor'?self::t('تسجيل دخول المورد','Vendor sign in'):self::t('تسجيل دخول العميل','Customer sign in')); ?></h1><p><?php echo esc_html(self::t('استخدم رقم الهاتف أو البريد الإلكتروني.','Use your phone number or email address.')); ?></p><?php wp_login_form(['redirect'=>self::url($type==='vendor'?'vendor-dashboard':'my-account'),'label_username'=>self::t('الهاتف أو البريد','Phone or email'),'label_password'=>self::t('كلمة المرور','Password'),'label_log_in'=>self::t('تسجيل الدخول','Sign in')]);?><a href="<?php echo esc_url(self::url($type==='vendor'?'vendor-register':'customer-register')); ?>"><?php echo esc_html(self::t('إنشاء حساب جديد','Create a new account')); ?></a></div></section><?php return ob_get_clean();}

    private static function user_orders($u){return get_posts(['post_type'=>'tager_order','numberposts'=>-1,'orderby'=>'date','order'=>'DESC','meta_query'=>['relation'=>'OR',['key'=>'customer_user','value'=>$u->ID],['key'=>'email','value'=>$u->user_email]]]);}
    private static function customer_overview($u){
        $orders=self::user_orders($u);$total=0;$open=0;foreach($orders as $o){$total+=(float)get_post_meta($o->ID,'total',true);$s=get_post_meta($o->ID,'order_status',true);if(!in_array($s,['Completed','Cancelled'],true))$open++;}
        ob_start(); ?><div class="t32-stats"><article><span><?php echo esc_html(self::t('إجمالي الطلبات','Total orders')); ?></span><b><?php echo count($orders); ?></b></article><article><span><?php echo esc_html(self::t('طلبات نشطة','Active orders')); ?></span><b><?php echo $open; ?></b></article><article><span><?php echo esc_html(self::t('إجمالي المشتريات','Total purchases')); ?></span><b><?php echo esc_html(self::money($total)); ?></b></article><article><span><?php echo esc_html(self::t('نقاط المكافآت','Reward points')); ?></span><b><?php echo intval(get_user_meta($u->ID,'tager_points',true)); ?></b></article></div>
        <div class="t32-grid"><section class="t32-card t32-span-2"><div class="t32-card-head"><h2><?php echo esc_html(self::t('آخر الطلبات','Recent orders')); ?></h2><a href="<?php echo esc_url(self::tab_url('my-account','orders')); ?>"><?php echo esc_html(self::t('عرض الكل','View all')); ?></a></div><?php echo self::orders_table(array_slice($orders,0,5),false); ?></section><section class="t32-card"><h2><?php echo esc_html(self::t('اختصارات سريعة','Quick actions')); ?></h2><div class="t32-quick"><a href="<?php echo esc_url(self::url('shop')); ?>">🛒 <?php echo esc_html(self::t('تسوق الآن','Shop now')); ?></a><a href="<?php echo esc_url(self::url('cart')); ?>">▣ <?php echo esc_html(self::t('فتح السلة','Open cart')); ?></a><a href="<?php echo esc_url(self::tab_url('my-account','addresses')); ?>">⌖ <?php echo esc_html(self::t('إدارة العناوين','Manage addresses')); ?></a></div></section></div><?php return ob_get_clean();
    }
    private static function customer_orders($u){return '<div class="t32-card"><div class="t32-card-head"><h2>'.esc_html(self::t('كل الطلبات','All orders')).'</h2></div>'.self::orders_table(self::user_orders($u),false).'</div>';}
    private static function orders_table($orders,$vendor=false){ob_start();?><div class="table-wrap"><table><thead><tr><th>#</th><th><?php echo esc_html(self::t('التاريخ','Date'));?></th><th><?php echo esc_html(self::t('الحالة','Status'));?></th><th><?php echo esc_html(self::t('الدفع','Payment'));?></th><th><?php echo esc_html(self::t('الإجمالي','Total'));?></th></tr></thead><tbody><?php if(!$orders):?><tr><td colspan="5"><?php echo esc_html(self::t('لا توجد بيانات حتى الآن.','No records yet.'));?></td></tr><?php endif;foreach($orders as $o):?><tr><td>#<?php echo intval($o->ID);?></td><td><?php echo esc_html(get_the_date('Y-m-d',$o));?></td><td><?php echo self::status_badge(get_post_meta($o->ID,'order_status',true));?></td><td><?php echo esc_html(get_post_meta($o->ID,'payment_method_name',true)?:get_post_meta($o->ID,'payment_status',true));?></td><td><?php echo esc_html(self::money(get_post_meta($o->ID,'total',true)));?></td></tr><?php endforeach;?></tbody></table></div><?php return ob_get_clean();}

    private static function customer_addresses($u){$gov=get_user_meta($u->ID,'governorate',true);$addr=get_user_meta($u->ID,'address',true);ob_start();?><div class="t32-grid"><section class="t32-card"><h2><?php echo esc_html(self::t('عنوان التوصيل الأساسي','Primary delivery address'));?></h2><p><strong><?php echo esc_html($gov?:self::t('لم يتم تحديد المحافظة','Governorate not set'));?></strong></p><p><?php echo nl2br(esc_html($addr?:self::t('أضف عنوانك لتسريع الطلب.','Add your address for faster checkout.')));?></p></section><section class="t32-card"><h2><?php echo esc_html(self::t('تحديث العنوان','Update address'));?></h2><?php echo self::customer_form($u,true);?></section></div><?php return ob_get_clean();}
    private static function customer_favorites(){return '<div class="t32-card t32-empty"><span>♡</span><h2>'.esc_html(self::t('قائمة المفضلة','Favorites')).'</h2><p>'.esc_html(self::t('سيتم عرض المنتجات التي تحفظها هنا.','Saved products will appear here.')).'</p><a class="btn primary" href="'.esc_url(self::url('shop')).'">'.esc_html(self::t('تصفح المنتجات','Browse products')).'</a></div>';}
    private static function customer_profile($u){return '<div class="t32-card"><h2>'.esc_html(self::t('بيانات الحساب','Account details')).'</h2>'.self::customer_form($u,false).'</div>';}
    private static function customer_form($u,$address_only=false){ob_start();?><form class="t32-form" method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><input type="hidden" name="action" value="tager_v32_save_customer"><?php wp_nonce_field('tager_v32_save_customer');?><?php if(!$address_only):?><div class="form-grid"><label><?php echo esc_html(self::t('الاسم الكامل','Full name'));?><input required name="name" value="<?php echo esc_attr($u->display_name);?>"></label><label><?php echo esc_html(self::t('رقم الهاتف','Phone'));?><input required name="phone" value="<?php echo esc_attr(get_user_meta($u->ID,'phone',true));?>"></label><label><?php echo esc_html(self::t('البريد الإلكتروني (اختياري)','Email (optional)'));?><input type="email" name="email" value="<?php echo esc_attr($u->user_email);?>"></label></div><?php endif;?><div class="form-grid"><label><?php echo esc_html(self::t('المحافظة','Governorate'));?><input name="governorate" value="<?php echo esc_attr(get_user_meta($u->ID,'governorate',true));?>"></label><label><?php echo esc_html(self::t('المدينة / المنطقة','City / district'));?><input name="city" value="<?php echo esc_attr(get_user_meta($u->ID,'city',true));?>"></label></div><label><?php echo esc_html(self::t('العنوان بالتفصيل','Detailed address'));?><textarea name="address"><?php echo esc_textarea(get_user_meta($u->ID,'address',true));?></textarea></label><button class="btn primary"><?php echo esc_html(self::t('حفظ التغييرات','Save changes'));?></button></form><?php return ob_get_clean();}

    private static function support_panel(){return '<div class="t32-grid"><section class="t32-card"><h2>'.esc_html(self::t('مركز المساعدة','Help center')).'</h2><p>'.esc_html(self::t('تواصل مع فريق الدعم لمتابعة الطلبات أو المدفوعات أو المرتجعات.','Contact support for orders, payments or returns.')).'</p><a class="btn primary" href="'.esc_url(home_url('/contact-us/')).'">'.esc_html(self::t('فتح تذكرة دعم','Open support ticket')).'</a></section><section class="t32-card"><h2>'.esc_html(self::t('الأسئلة الشائعة','Frequently asked questions')).'</h2><p>'.esc_html(self::t('راجع سياسات الشحن والاسترجاع والدفع.','Review shipping, returns and payment policies.')).'</p><a class="btn secondary" href="'.esc_url(home_url('/faq/')).'">'.esc_html(self::t('عرض الأسئلة','View FAQs')).'</a></section></div>';}

    public static function vendor_dashboard(){
        if(!is_user_logged_in()) return self::login_box('vendor');
        $u=wp_get_current_user();
        if(in_array('tager_vendor_pending',$u->roles,true)) return '<section class="t32-pending"><span>⌛</span><h1>'.esc_html(self::t('طلب المورد قيد المراجعة','Vendor application under review')).'</h1><p>'.esc_html(self::t('سنخبرك بمجرد اعتماد الحساب.','We will notify you once your account is approved.')).'</p><a class="btn secondary" href="'.esc_url(wp_logout_url(home_url('/'))).'">'.esc_html(self::t('تسجيل الخروج','Sign out')).'</a></section>';
        if(!in_array('tager_vendor',$u->roles,true)&&!current_user_can('manage_options')) return '<div class="notice">'.esc_html(self::t('هذا الحساب ليس حساب مورد.','This is not a vendor account.')).'</div>';
        $tab=sanitize_key($_GET['tab']??'overview');if(!isset(self::vendor_tabs()[$tab]))$tab='overview';
        if($tab==='overview')$content=self::vendor_overview($u);
        elseif($tab==='products')$content=self::vendor_products_panel($u);
        elseif($tab==='add-product')$content=self::vendor_add_product();
        elseif($tab==='orders')$content=self::vendor_orders_panel($u);
        elseif($tab==='earnings')$content=self::vendor_earnings($u);
        elseif($tab==='store')$content=self::vendor_store($u);
        else $content=self::vendor_profile($u);
        return self::shell('vendor',get_user_meta($u->ID,'store_name',true)?:$u->display_name,self::t('إدارة متجرك ومنتجاتك وطلباتك وأرباحك.','Manage your store, products, orders and earnings.'),self::vendor_tabs(),$tab,$content);
    }

    private static function vendor_orders_list($uid){$orders=get_posts(['post_type'=>'tager_order','numberposts'=>-1,'orderby'=>'date','order'=>'DESC']);$out=[];foreach($orders as $o){foreach((array)get_post_meta($o->ID,'items',true) as $i){if((int)get_post_field('post_author',(int)($i['id']??0))===$uid){$out[]=$o;break;}}}return $out;}
    private static function vendor_sales($uid,$completed_only=false){$sum=0;foreach(self::vendor_orders_list($uid) as $o){$status=get_post_meta($o->ID,'order_status',true);if($completed_only&&$status!=='Completed')continue;foreach((array)get_post_meta($o->ID,'items',true) as $i)if((int)get_post_field('post_author',(int)($i['id']??0))===$uid)$sum+=(float)($i['line_total']??0);}return $sum;}
    private static function vendor_overview($u){$products=get_posts(['post_type'=>'tager_product','author'=>$u->ID,'post_status'=>['publish','pending','draft'],'numberposts'=>-1]);$orders=self::vendor_orders_list($u->ID);$sales=self::vendor_sales($u->ID);$pending=0;foreach($products as $p)if(get_post_meta($p->ID,'approval_status',true)!=='approved')$pending++;ob_start();?><div class="t32-stats"><article><span><?php echo esc_html(self::t('المنتجات','Products'));?></span><b><?php echo count($products);?></b></article><article><span><?php echo esc_html(self::t('تحت المراجعة','Pending review'));?></span><b><?php echo $pending;?></b></article><article><span><?php echo esc_html(self::t('الطلبات','Orders'));?></span><b><?php echo count($orders);?></b></article><article><span><?php echo esc_html(self::t('إجمالي المبيعات','Gross sales'));?></span><b><?php echo esc_html(self::money($sales));?></b></article></div><div class="t32-grid"><section class="t32-card t32-span-2"><div class="t32-card-head"><h2><?php echo esc_html(self::t('آخر الطلبات','Recent orders'));?></h2><a href="<?php echo esc_url(self::tab_url('vendor-dashboard','orders'));?>"><?php echo esc_html(self::t('عرض الكل','View all'));?></a></div><?php echo self::orders_table(array_slice($orders,0,5),true);?></section><section class="t32-card"><h2><?php echo esc_html(self::t('حالة المتجر','Store status'));?></h2><div class="t32-progress"><span style="width:<?php echo intval(self::store_completion($u));?>%"></span></div><p><?php echo intval(self::store_completion($u));?>% <?php echo esc_html(self::t('مكتمل','complete'));?></p><a class="btn secondary" href="<?php echo esc_url(self::tab_url('vendor-dashboard','store'));?>"><?php echo esc_html(self::t('استكمال البيانات','Complete setup'));?></a></section></div><?php return ob_get_clean();}
    private static function store_completion($u){$fields=['store_name','phone','vendor_min_order','store_description','store_address','bank_name','iban'];$done=0;foreach($fields as $f)if(get_user_meta($u->ID,$f,true))$done++;return round(($done/count($fields))*100);}

    private static function vendor_products_panel($u){$q=new WP_Query(['post_type'=>'tager_product','author'=>$u->ID,'post_status'=>['publish','pending','draft'],'posts_per_page'=>-1]);ob_start();?><div class="t32-card"><div class="t32-card-head"><h2><?php echo esc_html(self::t('منتجاتي','My products'));?></h2><a class="btn primary" href="<?php echo esc_url(self::tab_url('vendor-dashboard','add-product'));?>">+ <?php echo esc_html(self::t('منتج جديد','New product'));?></a></div><div class="table-wrap"><table><thead><tr><th><?php echo esc_html(self::t('المنتج','Product'));?></th><th><?php echo esc_html(self::t('السعر','Price'));?></th><th><?php echo esc_html(self::t('المخزون','Stock'));?></th><th><?php echo esc_html(self::t('الحالة','Status'));?></th></tr></thead><tbody><?php if(!$q->have_posts()):?><tr><td colspan="4"><?php echo esc_html(self::t('لم تضف منتجات بعد.','No products yet.'));?></td></tr><?php endif;while($q->have_posts()):$q->the_post();$id=get_the_ID();?><tr><td><strong><?php echo esc_html(get_the_title());?></strong><br><small><?php echo esc_html(get_post_meta($id,'category_name',true));?></small></td><td><?php echo esc_html(self::money(get_post_meta($id,'retail_price',true)));?></td><td><?php echo intval(get_post_meta($id,'stock',true));?></td><td><?php echo self::status_badge(get_post_meta($id,'approval_status',true)?:get_post_status());?></td></tr><?php endwhile;wp_reset_postdata();?></tbody></table></div></div><?php return ob_get_clean();}
    private static function vendor_add_product(){ob_start();?><div class="t32-card"><h2><?php echo esc_html(self::t('إضافة منتج جديد','Add a new product'));?></h2><p><?php echo esc_html(self::t('أدخل بيانات المنتج والأسعار الثلاثة. سيتم إرساله للمراجعة قبل النشر.','Enter product details and all pricing tiers. It will be reviewed before publishing.'));?></p><form class="t32-form" method="post" enctype="multipart/form-data" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><input type="hidden" name="action" value="tager_add_product"><?php wp_nonce_field('tager_add_product');?><div class="form-grid"><label><?php echo esc_html(self::t('الاسم بالعربي','Arabic name'));?><input required name="title_ar"></label><label><?php echo esc_html(self::t('الاسم بالإنجليزي','English name'));?><input required name="title_en"></label><label><?php echo esc_html(self::t('القسم','Category'));?><input required name="category_name"></label><label><?php echo esc_html(self::t('المخزون','Stock'));?><input required type="number" min="0" name="stock"></label><label><?php echo esc_html(self::t('سعر القطاعي','Retail price'));?><input required type="number" step="0.01" min="0" name="retail"></label><label><?php echo esc_html(self::t('سعر الجملة','Wholesale price'));?><input required type="number" step="0.01" min="0" name="wholesale"></label><label><?php echo esc_html(self::t('سعر جملة الجملة','Bulk price'));?><input required type="number" step="0.01" min="0" name="bulk"></label><label><?php echo esc_html(self::t('حد الجملة','Wholesale minimum'));?><input required type="number" min="1" name="wholesale_min"></label><label><?php echo esc_html(self::t('حد جملة الجملة','Bulk minimum'));?><input required type="number" min="1" name="bulk_min"></label><label><?php echo esc_html(self::t('أقصى كمية للطلب','Maximum order quantity'));?><input required type="number" min="1" name="max_qty"></label></div><label><?php echo esc_html(self::t('الوصف','Description'));?><textarea required name="description"></textarea></label><label><?php echo esc_html(self::t('صورة المنتج','Product image'));?><input type="file" accept="image/jpeg,image/png,image/webp" name="product_image"></label><button class="btn primary"><?php echo esc_html(self::t('حفظ وإرسال للمراجعة','Save and submit for review'));?></button></form></div><?php return ob_get_clean();}
    private static function vendor_orders_panel($u){return '<div class="t32-card"><h2>'.esc_html(self::t('طلبات منتجاتي','Orders for my products')).'</h2>'.self::orders_table(self::vendor_orders_list($u->ID),true).'</div>';}
    private static function vendor_earnings($u){$gross=self::vendor_sales($u->ID);$settings=wp_parse_args(get_option('tager_settings',[]),['commission_percent'=>10]);$commission=$gross*((float)$settings['commission_percent']/100);$net=$gross-$commission;$completed=self::vendor_sales($u->ID,true);ob_start();?><div class="t32-stats"><article><span><?php echo esc_html(self::t('إجمالي المبيعات','Gross sales'));?></span><b><?php echo esc_html(self::money($gross));?></b></article><article><span><?php echo esc_html(self::t('عمولة المنصة','Platform commission'));?></span><b><?php echo esc_html(self::money($commission));?></b></article><article><span><?php echo esc_html(self::t('صافي المستحق','Net earnings'));?></span><b><?php echo esc_html(self::money($net));?></b></article><article><span><?php echo esc_html(self::t('مبيعات مكتملة','Completed sales'));?></span><b><?php echo esc_html(self::money($completed));?></b></article></div><div class="t32-card"><h2><?php echo esc_html(self::t('بيانات التحويل','Payout information'));?></h2><p><?php echo esc_html(get_user_meta($u->ID,'bank_name',true)?:self::t('لم يتم إدخال اسم البنك.','Bank name not set.'));?></p><p><?php echo esc_html(get_user_meta($u->ID,'iban',true)?:self::t('لم يتم إدخال رقم IBAN.','IBAN not set.'));?></p><a class="btn secondary" href="<?php echo esc_url(self::tab_url('vendor-dashboard','store'));?>"><?php echo esc_html(self::t('تحديث بيانات التحويل','Update payout details'));?></a></div><?php return ob_get_clean();}
    private static function vendor_store($u){ob_start();?><div class="t32-card"><h2><?php echo esc_html(self::t('إعدادات المتجر','Store settings'));?></h2><form class="t32-form" method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><input type="hidden" name="action" value="tager_v32_save_vendor"><?php wp_nonce_field('tager_v32_save_vendor');?><input type="hidden" name="section" value="store"><div class="form-grid"><label><?php echo esc_html(self::t('اسم المتجر','Store name'));?><input required name="store_name" value="<?php echo esc_attr(get_user_meta($u->ID,'store_name',true));?>"></label><label><?php echo esc_html(self::t('الحد الأدنى للطلب','Minimum order'));?><input type="number" min="0" step="0.01" name="vendor_min_order" value="<?php echo esc_attr(get_user_meta($u->ID,'vendor_min_order',true));?>"></label><label><?php echo esc_html(self::t('هاتف المتجر','Store phone'));?><input name="phone" value="<?php echo esc_attr(get_user_meta($u->ID,'phone',true));?>"></label><label><?php echo esc_html(self::t('المحافظة','Governorate'));?><input name="governorate" value="<?php echo esc_attr(get_user_meta($u->ID,'governorate',true));?>"></label></div><label><?php echo esc_html(self::t('وصف المتجر','Store description'));?><textarea name="store_description"><?php echo esc_textarea(get_user_meta($u->ID,'store_description',true));?></textarea></label><label><?php echo esc_html(self::t('عنوان المتجر','Store address'));?><textarea name="store_address"><?php echo esc_textarea(get_user_meta($u->ID,'store_address',true));?></textarea></label><div class="form-grid"><label><?php echo esc_html(self::t('اسم البنك','Bank name'));?><input name="bank_name" value="<?php echo esc_attr(get_user_meta($u->ID,'bank_name',true));?>"></label><label><?php echo esc_html(self::t('IBAN / رقم الحساب','IBAN / account number'));?><input name="iban" value="<?php echo esc_attr(get_user_meta($u->ID,'iban',true));?>"></label></div><button class="btn primary"><?php echo esc_html(self::t('حفظ إعدادات المتجر','Save store settings'));?></button></form></div><?php return ob_get_clean();}
    private static function vendor_profile($u){ob_start();?><div class="t32-grid"><section class="t32-card"><h2><?php echo esc_html(self::t('بيانات الحساب','Account information'));?></h2><form class="t32-form" method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><input type="hidden" name="action" value="tager_v32_save_vendor"><?php wp_nonce_field('tager_v32_save_vendor');?><input type="hidden" name="section" value="profile"><label><?php echo esc_html(self::t('الاسم','Name'));?><input required name="name" value="<?php echo esc_attr($u->display_name);?>"></label><label><?php echo esc_html(self::t('البريد الإلكتروني (اختياري)','Email (optional)'));?><input type="email" name="email" value="<?php echo esc_attr($u->user_email);?>"></label><label><?php echo esc_html(self::t('رقم الهاتف','Phone'));?><input required name="phone" value="<?php echo esc_attr(get_user_meta($u->ID,'phone',true));?>"></label><button class="btn primary"><?php echo esc_html(self::t('حفظ البيانات','Save details'));?></button></form></section><section class="t32-card"><h2><?php echo esc_html(self::t('الأمان','Security'));?></h2><p><?php echo esc_html(self::t('يمكنك تغيير كلمة المرور من صفحة استعادة كلمة المرور.','You can reset your password using the password recovery page.'));?></p><a class="btn secondary" href="<?php echo esc_url(wp_lostpassword_url());?>"><?php echo esc_html(self::t('تغيير كلمة المرور','Change password'));?></a></section></div><?php return ob_get_clean();}

    public static function save_customer(){if(!is_user_logged_in())wp_die('Login required');check_admin_referer('tager_v32_save_customer');$u=wp_get_current_user();$name=sanitize_text_field($_POST['name']??$u->display_name);$email=sanitize_email($_POST['email']??$u->user_email);if($email&&email_exists($email)&&email_exists($email)!=$u->ID)wp_die('Email already used');wp_update_user(['ID'=>$u->ID,'display_name'=>$name,'user_email'=>$email]);foreach(['phone','governorate','city','address'] as $f)if(isset($_POST[$f]))update_user_meta($u->ID,$f,sanitize_textarea_field($_POST[$f]));wp_safe_redirect(add_query_arg(['tab'=>sanitize_key($_GET['tab']??'profile'),'saved'=>1],self::url('my-account')));exit;}
    public static function save_vendor(){if(!is_user_logged_in())wp_die('Login required');check_admin_referer('tager_v32_save_vendor');$u=wp_get_current_user();if(!in_array('tager_vendor',$u->roles,true)&&!current_user_can('manage_options'))wp_die('Not allowed');$section=sanitize_key($_POST['section']??'store');if($section==='profile'){wp_update_user(['ID'=>$u->ID,'display_name'=>sanitize_text_field($_POST['name']??$u->display_name),'user_email'=>sanitize_email($_POST['email']??$u->user_email)]);update_user_meta($u->ID,'phone',sanitize_text_field($_POST['phone']??''));$tab='profile';}else{foreach(['store_name','vendor_min_order','phone','governorate','store_description','store_address','bank_name','iban'] as $f)update_user_meta($u->ID,$f,sanitize_textarea_field($_POST[$f]??''));$tab='store';}wp_safe_redirect(add_query_arg(['tab'=>$tab,'saved'=>1],self::url('vendor-dashboard')));exit;}

    private static function css(){return <<<'CSS'
.t32-shell{display:grid;grid-template-columns:250px minmax(0,1fr);min-height:78vh;background:#f6f7f5;border-radius:24px;overflow:hidden;margin:28px auto;max-width:1380px;box-shadow:0 18px 50px rgba(20,50,36,.08)}.t32-sidebar{background:linear-gradient(180deg,#0f3d2b,#09271c);color:#fff;padding:24px 16px;display:flex;flex-direction:column}.t32-brand{display:flex;align-items:center;gap:12px;padding:4px 8px 24px}.t32-brand strong{display:block;font-size:22px}.t32-brand small{opacity:.7}.t32-logo{width:42px;height:42px;border-radius:14px;display:grid;place-items:center;background:#d5ad45;color:#0f3d2b;font-weight:900;font-size:22px}.t32-nav{display:grid;gap:6px}.t32-nav a,.t32-side-foot a{color:#fff;text-decoration:none;padding:12px 14px;border-radius:12px;display:flex;gap:10px;align-items:center}.t32-nav a:hover,.t32-nav a.active{background:rgba(255,255,255,.12)}.t32-nav a.active{box-shadow:inset 3px 0 #d5ad45}.t32-side-foot{margin-top:auto;display:grid;gap:4px;padding-top:20px;border-top:1px solid rgba(255,255,255,.12)}.t32-main{min-width:0}.t32-top{display:flex;justify-content:space-between;gap:20px;align-items:center;padding:28px 30px;background:#fff;border-bottom:1px solid #e7ece8}.t32-top h1{margin:0;font-size:28px;color:#153b2c}.t32-top p{margin:5px 0 0;color:#6c786f}.t32-content{padding:28px}.t32-stats{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:16px;margin-bottom:20px}.t32-stats article,.t32-card{background:#fff;border:1px solid #e4e9e5;border-radius:18px;padding:20px}.t32-stats span{display:block;color:#748078;font-size:13px}.t32-stats b{display:block;margin-top:8px;font-size:26px;color:#123d2b}.t32-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}.t32-span-2{grid-column:span 2}.t32-card h2{margin-top:0;color:#173f2f}.t32-card-head{display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:14px}.t32-card-head a{text-decoration:none}.t32-quick{display:grid;gap:10px}.t32-quick a{padding:13px;border-radius:12px;background:#f3f7f4;text-decoration:none;color:#153b2c}.t32-badge{display:inline-flex;padding:5px 10px;border-radius:999px;background:#eef1ef;font-size:12px}.t32-approved,.t32-completed{background:#e3f7ea;color:#16723c}.t32-pending,.t32-awaiting-payment,.t32-new{background:#fff4d5;color:#8b6400}.t32-cancelled,.t32-rejected{background:#fde5e5;color:#a62b2b}.t32-progress{height:9px;background:#edf1ee;border-radius:999px;overflow:hidden}.t32-progress span{display:block;height:100%;background:#d5ad45}.t32-form{display:grid;gap:15px}.t32-form label{display:grid;gap:7px;font-weight:700;color:#294638}.t32-form input,.t32-form textarea,.t32-form select{width:100%;border:1px solid #ccd6cf;border-radius:12px;padding:12px;background:#fff}.t32-form textarea{min-height:110px}.t32-empty{text-align:center;padding:55px 20px}.t32-empty>span{font-size:50px;color:#d5ad45}.t32-login,.t32-pending{max-width:620px;margin:50px auto;background:#fff;border-radius:24px;padding:34px;box-shadow:0 18px 55px rgba(20,50,36,.12)}.t32-pending{text-align:center}.t32-pending>span{font-size:54px}.table-wrap{overflow:auto}.table-wrap table{width:100%;border-collapse:collapse}.table-wrap th,.table-wrap td{padding:13px;border-bottom:1px solid #edf0ee;text-align:start;white-space:nowrap}.table-wrap th{font-size:12px;color:#6f7a73;background:#f8faf8}.t32-shell .btn{display:inline-flex;align-items:center;justify-content:center}.rtl .t32-nav a.active{box-shadow:inset -3px 0 #d5ad45}
@media(max-width:980px){.t32-shell{grid-template-columns:1fr;margin:12px}.t32-sidebar{position:static}.t32-nav{grid-template-columns:repeat(3,minmax(0,1fr))}.t32-side-foot{grid-template-columns:1fr 1fr}.t32-stats{grid-template-columns:repeat(2,1fr)}.t32-grid{grid-template-columns:1fr}.t32-span-2{grid-column:auto}}
@media(max-width:620px){.t32-nav{grid-template-columns:1fr 1fr}.t32-top{padding:20px;align-items:flex-start}.t32-content{padding:15px}.t32-stats{grid-template-columns:1fr}.form-grid{grid-template-columns:1fr!important}.t32-card{padding:16px}}
CSS;}
}
